(17, 3, 1, 1, 'BIRTHDAY_SMS_002', '亲爱的演示客户，生日快乐！专属生日特权已送达您的账户，本月消费享双倍积分，祝您拥有美好的一天！', 1, '2026-07-13 08:45:00', '发送失败-号码无效', 1, 'admin', 'admin'),
(14, NULL, 1, 1, 'BIRTHDAY_SMS_001', '尊敬的啦啦啦，生日快乐！愿您的生活如阳光般灿烂，我们为您准备了一份生日惊喜，期待您的光临。', 0, '2026-07-10 11:20:00', '系统自动发送', 1, 'admin', 'admin'),

