(13, 18, 2, 2, 'MID_AUTUMN_001', '<h2>中秋快乐！</h2><p>亲爱的呵呵哒，月圆人团圆，中秋佳节来临之际，我们诚挚祝福您阖家欢乐、幸福美满！为您准备了中秋精美礼盒，欢迎选购。</p>', 0, '2026-07-08 14:00:00', '中秋营销活动', 1, 'admin', 'admin'),
(16, 7, 2, 1, 'QIXI_SMS_001', '七夕情人节快乐！演示线索您好，爱在七夕，为您精选多款情侣好礼，限时特惠进行中，点击查看详情>>', 0, '2026-07-07 09:15:00', '七夕专题活动', 1, 'admin', 'admin'),
(12, 21, 2, 2, 'NEWYEAR_EMAIL_001', '<h2>元旦快乐！</h2><p>新的一年，新的开始！感谢您过去一年的信任与陪伴，祝您元旦快乐、新年大吉！</p>', 0, '2026-07-06 16:30:00', '元旦跨年活动', 1, 'admin', 'admin'),
(15, 9, 2, 1, 'MEMBER_DAY_SMS', '小土豆您好，会员日专享福利已上线！全场8折起，限时48小时，快来选购吧！', 1, '2026-07-05 10:30:00', '发送失败-运营商限流', 1, 'admin', 'admin'),
(17, 12, 2, 2, 'GROUP_BUY_EMAIL', '<h2>企业团购季</h2><p>尊敬的演示客户，企业团购季火热进行中，满10件享85折，满50件享7折，欢迎咨询团购方案。</p>', 0, '2026-07-04 13:45:00', '企业团购活动', 1, 'admin', 'admin'),

