(12, NULL, 3, 1, 'MANUAL_FOLLOWUP', '王先生您好，感谢您上周参与我们的产品体验活动，请问对产品使用有什么问题或建议吗？随时联系我们。', 0, '2026-07-16 15:00:00', '售后回访跟进', 1, 'admin', 'admin'),
